     * If target is $0^{n-1} 1$: Flips = $\sum_{i=0}^{n-2} [s[i] = '1'] + [s[n-1] = '0']$.
     * 
     * Case 4: Target $1 0^b$ (where $b = n-1$). This is only possible if $n>0$.
     * If $n>0$, we try to make it $1 0^{n-1}$. Cost = $[s[0] = '0'] + \sum_{i=1}^{n-1} [s[i] = '1']$.
     * 
     * We take the minimum of the costs from all achievable target structures.
     */
    public static long solve(String s) {
        int n = s.length();
        if (n == 0) return 0;

        // Case 1: Target 0^n (All zeros)
        long cost_0_n = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '1') {
                cost_0_n++;
            }
        }

        // Case 2: Target 1^n (All ones)
        long cost_1_n = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '0') {
                cost_1_n++;
            }
        }

        long min_cost = Math.min(cost_0_n, cost_1_n);

        // Case 3: Target 0^(n-1) 1
        // This is the target string s_target where s_target[i] = '0' for i < n-1, and s_target[n-1] = '1'.
        if (n > 0) {
            long cost_0_n_minus_1_1 = 0;
            // Flips for first n-1 positions to be '0'
            for (int i = 0; i < n - 1; i++) {
                if (s.charAt(i) == '1') {
                    cost_0_n_minus_1_1++;
                }
            }
            // Flip for the last position to be '1'
            if (s.charAt(n - 1) == '0') {
                cost_0_n_minus_1_1++;
            }
            min_cost = Math.min(min_cost, cost_0_n_minus_1_1);
        }

        // Case 4: Target 1 0^(n-1)
        // This is the target string s_target where s_target[0] = '1', and s_target[i] = '0' for i > 0.
        if (n > 0) {
            long cost_1_0_n_minus_1 = 0;
            // Flip for the first position to be '1'
            if (s.charAt(0) == '0') {
                cost_1_0_n_minus_1++;
            }
            // Flips for remaining n-1 positions to be '0'
            for (int i = 1; i < n; i++) {
                if (s.charAt(i) == '1') {
                    cost_1_0_n_minus_1++;
                }
            }
            min_cost = Math.min(min_cost, cost_1_0_n_minus_1);
        }

        return min_cost;
    }
